"use client"

import { useState, useEffect } from "react"
import { useDataStore } from "@/store/data-store"
import { useAuthStore } from "@/store/auth-store"
import { EntityStatusBadge } from "@/components/shared/status-badge"
import { ConfirmDialog } from "@/components/shared/confirm-dialog"
import { Card, CardContent } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Textarea } from "@/components/ui/textarea"
import { Badge } from "@/components/ui/badge"
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "@/components/ui/dialog"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu"
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table"
import {
  MoreHorizontal,
  Pencil,
  Trash2,
  Search,
  Plus,
  GitBranch,
  Users,
  UserCog,
  Building2,
  CheckCircle2,
  AlertTriangle,
  FileText,
} from "lucide-react"
import { toast } from "sonner"
import { cn } from "@/lib/utils"
import type { EntityStatus } from "@/lib/types"

interface Branch {
  id: string
  name: string
  description: string | null
  dmaId: string
  dmaName: string
  utilityId: string
  utilityName: string
  status: string
  engineerCount: number
  teamCount: number
  reportCount: number
  createdAt: string
  updatedAt: string
}

export default function BranchesPage() {
  const { currentUser } = useAuthStore()
  const { dmas, fetchDMAs } = useDataStore()
  const [branches, setBranches] = useState<Branch[]>([])
  const [search, setSearch] = useState("")
  const [dialogOpen, setDialogOpen] = useState(false)
  const [editingBranch, setEditingBranch] = useState<Branch | null>(null)
  const [deleteBranch, setDeleteBranch] = useState<Branch | null>(null)

  // Form state
  const [formName, setFormName] = useState("")
  const [formDescription, setFormDescription] = useState("")
  const [formStatus, setFormStatus] = useState<EntityStatus>("active")

  // Fetch data on mount
  useEffect(() => {
    fetchDMAs()
    fetchBranches()
  }, [fetchDMAs])

  async function fetchBranches() {
    try {
      const dmaId = currentUser?.dmaId
      const url = dmaId ? `/api/branches?dmaId=${dmaId}` : "/api/branches"
      const response = await fetch(url)
      if (response.ok) {
        const data = await response.json()
        setBranches(data)
      }
    } catch (error) {
      console.error("Error fetching branches:", error)
    }
  }

  // Only DMA managers can access this page
  const isDMAManager = currentUser?.role === "dma_manager"
  
  // Get DMA info
  const dmaId = currentUser?.dmaId ?? ""
  const dma = dmas.find((d) => d.id === dmaId)
  const utilityId = currentUser?.utilityId ?? ""
  const utilityName = currentUser?.utilityName ?? "Your Utility"

  if (!isDMAManager) {
    return (
      <div className="flex flex-col gap-6">
        <Card className="border-slate-200/60 shadow-lg shadow-slate-200/20">
          <CardContent className="py-16 text-center">
            <div className="flex flex-col items-center gap-4">
              <div className="h-16 w-16 rounded-2xl bg-gradient-to-br from-slate-100 to-slate-200 flex items-center justify-center">
                <GitBranch className="h-8 w-8 text-slate-400" />
              </div>
              <div>
                <p className="text-lg font-semibold text-slate-800">Access Restricted</p>
                <p className="text-sm text-slate-500 mt-1">Only DMA Managers can manage branches</p>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>
    )
  }

  const filteredBranches = branches.filter((b) =>
    b.name.toLowerCase().includes(search.toLowerCase())
  )

  // Stats
  const totalBranches = branches.length
  const activeBranches = branches.filter(b => b.status === "active").length

  function openCreateDialog() {
    setEditingBranch(null)
    setFormName("")
    setFormDescription("")
    setFormStatus("active")
    setDialogOpen(true)
  }

  function openEditDialog(branch: Branch) {
    setEditingBranch(branch)
    setFormName(branch.name)
    setFormDescription(branch.description || "")
    setFormStatus(branch.status as EntityStatus)
    setDialogOpen(true)
  }

  async function handleSubmit() {
    if (!formName.trim()) {
      toast.error("Branch name is required")
      return
    }

    try {
      if (editingBranch) {
        // Update existing branch
        const response = await fetch("/api/branches", {
          method: "PUT",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            id: editingBranch.id,
            name: formName,
            description: formDescription || null,
            status: formStatus,
          }),
        })

        if (!response.ok) {
          const error = await response.json()
          throw new Error(error.error || "Failed to update branch")
        }

        toast.success("Branch updated successfully")
      } else {
        // Create new branch
        const response = await fetch("/api/branches", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            name: formName,
            description: formDescription || null,
            dmaId: dmaId,
            utilityId: utilityId,
            status: formStatus,
          }),
        })

        if (!response.ok) {
          const error = await response.json()
          throw new Error(error.error || "Failed to create branch")
        }

        toast.success("Branch created successfully")
      }

      setDialogOpen(false)
      await fetchBranches()
    } catch (error) {
      console.error("Error saving branch:", error)
      toast.error(error instanceof Error ? error.message : "Failed to save branch")
    }
  }

  async function handleDelete() {
    if (!deleteBranch) return

    try {
      const response = await fetch(`/api/branches?id=${deleteBranch.id}`, {
        method: "DELETE",
      })

      if (!response.ok) {
        const error = await response.json()
        throw new Error(error.error || "Failed to delete branch")
      }

      toast.success("Branch deleted successfully")
      setDeleteBranch(null)
      await fetchBranches()
    } catch (error) {
      console.error("Error deleting branch:", error)
      toast.error(error instanceof Error ? error.message : "Failed to delete branch")
    }
  }

  // Get initials for avatar
  const getInitials = (name: string) => {
    return name
      .split(" ")
      .map((n) => n[0])
      .join("")
      .toUpperCase()
      .slice(0, 2)
  }

  return (
    <div className="flex flex-col gap-6">
      {/* Modern Header with Stats */}
      <div className="flex flex-col gap-6">
        <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
          <div>
            <h1 className="text-2xl font-bold text-slate-800 flex items-center gap-3">
              <div className="h-10 w-10 rounded-xl bg-gradient-to-br from-cyan-500 to-blue-600 flex items-center justify-center shadow-lg shadow-cyan-500/20">
                <GitBranch className="h-5 w-5 text-white" />
              </div>
              Branch Management
            </h1>
            <p className="text-slate-500 mt-1">
              Manage branches for {dma?.name || "your DMA"}
            </p>
          </div>
          <Button 
            onClick={openCreateDialog}
            className="bg-gradient-to-r from-cyan-500 to-blue-600 hover:from-cyan-600 hover:to-blue-700 text-white shadow-lg shadow-cyan-500/25 hover:shadow-cyan-500/40 transition-all duration-300 rounded-xl h-11 px-6"
          >
            <Plus className="h-4 w-4 mr-2" />
            Add Branch
          </Button>
        </div>

        {/* Stats Cards */}
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
          <Card className="border-slate-200/60 shadow-lg shadow-slate-200/20 overflow-hidden group hover:shadow-xl hover:shadow-cyan-500/10 transition-all duration-300 bg-gradient-to-br from-cyan-50/30 to-white">
            <CardContent className="p-5">
              <div className="flex items-center gap-4">
                <div className="h-12 w-12 rounded-xl bg-gradient-to-br from-cyan-500 to-blue-600 flex items-center justify-center shadow-lg shadow-cyan-500/20 group-hover:scale-110 transition-transform duration-300">
                  <GitBranch className="h-6 w-6 text-white" />
                </div>
                <div>
                  <p className="text-sm font-medium text-slate-500">Total Branches</p>
                  <p className="text-2xl font-bold text-slate-800">{totalBranches}</p>
                </div>
              </div>
            </CardContent>
          </Card>

          <Card className="border-slate-200/60 shadow-lg shadow-slate-200/20 overflow-hidden group hover:shadow-xl hover:shadow-green-500/10 transition-all duration-300 bg-gradient-to-br from-green-50/30 to-white">
            <CardContent className="p-5">
              <div className="flex items-center gap-4">
                <div className="h-12 w-12 rounded-xl bg-gradient-to-br from-green-500 to-emerald-600 flex items-center justify-center shadow-lg shadow-green-500/20 group-hover:scale-110 transition-transform duration-300">
                  <CheckCircle2 className="h-6 w-6 text-white" />
                </div>
                <div>
                  <p className="text-sm font-medium text-slate-500">Active Branches</p>
                  <p className="text-2xl font-bold text-slate-800">{activeBranches}</p>
                </div>
              </div>
            </CardContent>
          </Card>

          <Card className="border-slate-200/60 shadow-lg shadow-slate-200/20 overflow-hidden group hover:shadow-xl hover:shadow-violet-500/10 transition-all duration-300 bg-gradient-to-br from-violet-50/30 to-white">
            <CardContent className="p-5">
              <div className="flex items-center gap-4">
                <div className="h-12 w-12 rounded-xl bg-gradient-to-br from-violet-500 to-purple-600 flex items-center justify-center shadow-lg shadow-violet-500/20 group-hover:scale-110 transition-transform duration-300">
                  <Building2 className="h-6 w-6 text-white" />
                </div>
                <div>
                  <p className="text-sm font-medium text-slate-500">Utility</p>
                  <p className="text-lg font-bold text-slate-800 truncate max-w-[150px]">{utilityName}</p>
                </div>
              </div>
            </CardContent>
          </Card>
        </div>
      </div>

      {/* Modern Search */}
      <div className="flex flex-col sm:flex-row gap-4 items-start sm:items-center justify-between">
        <div className="relative w-full sm:w-80">
          <div className="absolute inset-0 rounded-xl bg-gradient-to-r from-cyan-400/10 to-blue-500/10 blur-lg opacity-0 focus-within:opacity-100 transition-opacity duration-300 pointer-events-none" />
          <Search className="absolute left-4 top-1/2 h-4 w-4 -translate-y-1/2 text-slate-400 pointer-events-none" />
          <Input
            placeholder="Search branches..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="pl-11 h-11 bg-slate-50/80 border-slate-200/80 rounded-xl focus:border-cyan-400 focus:ring-cyan-400/20 shadow-sm"
          />
        </div>
        <div className="flex items-center gap-2 text-sm text-slate-500">
          <GitBranch className="h-4 w-4" />
          <span>{filteredBranches.length} branch{filteredBranches.length !== 1 ? 'es' : ''}</span>
        </div>
      </div>

      {/* Modern Table */}
      <Card className="border-slate-200/60 shadow-lg shadow-slate-200/20 overflow-hidden">
        <CardContent className="p-0">
          <div className="overflow-x-auto">
            <Table>
              <TableHeader>
                <TableRow className="bg-gradient-to-r from-slate-50 to-slate-100/80 hover:from-slate-50 hover:to-slate-100/80 border-b border-slate-200/60">
                  <TableHead className="font-semibold text-slate-600 py-4 px-6">
                    <div className="flex items-center gap-2">
                      <GitBranch className="h-4 w-4" />
                      Branch
                    </div>
                  </TableHead>
                  <TableHead className="font-semibold text-slate-600 py-4 px-6 text-center">
                    <div className="flex items-center justify-center gap-2">
                      <UserCog className="h-4 w-4" />
                      Engineers
                    </div>
                  </TableHead>
                  <TableHead className="font-semibold text-slate-600 py-4 px-6 text-center">
                    <div className="flex items-center justify-center gap-2">
                      <Users className="h-4 w-4" />
                      Teams
                    </div>
                  </TableHead>
                  <TableHead className="font-semibold text-slate-600 py-4 px-6">
                    <div className="flex items-center gap-2">
                      <CheckCircle2 className="h-4 w-4" />
                      Status
                    </div>
                  </TableHead>
                  <TableHead className="font-semibold text-slate-600 py-4 px-6 text-right">Actions</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {filteredBranches.length === 0 ? (
                  <TableRow>
                    <TableCell colSpan={5} className="py-16 text-center">
                      <div className="flex flex-col items-center gap-4">
                        <div className="h-16 w-16 rounded-2xl bg-gradient-to-br from-slate-100 to-slate-200 flex items-center justify-center">
                          <GitBranch className="h-8 w-8 text-slate-400" />
                        </div>
                        <div>
                          <p className="text-lg font-semibold text-slate-800">No branches found</p>
                          <p className="text-sm text-slate-500 mt-1">
                            {search ? "Try adjusting your search terms" : "Get started by creating your first branch"}
                          </p>
                        </div>
                        {!search && (
                          <Button 
                            onClick={openCreateDialog}
                            className="mt-2 bg-gradient-to-r from-cyan-500 to-blue-600 hover:from-cyan-600 hover:to-blue-700 text-white shadow-lg shadow-cyan-500/25 rounded-xl"
                          >
                            <Plus className="h-4 w-4 mr-2" />
                            Add Branch
                          </Button>
                        )}
                      </div>
                    </TableCell>
                  </TableRow>
                ) : (
                  filteredBranches.map((branch) => {
                    const isInactive = branch.status === "inactive"
                    const hasData = branch.engineerCount > 0 || branch.teamCount > 0 || branch.reportCount > 0
                    
                    return (
                      <TableRow 
                        key={branch.id} 
                        className={cn(
                          "border-b border-slate-100 transition-all duration-200",
                          isInactive 
                            ? "bg-red-50/30 hover:bg-red-50/50" 
                            : "hover:bg-cyan-50/50"
                        )}
                      >
                        {/* Branch Info */}
                        <TableCell className="py-4 px-6">
                          <div className="flex items-center gap-3">
                            <div className={cn(
                              "h-10 w-10 rounded-lg flex items-center justify-center shadow-lg",
                              isInactive 
                                ? "bg-gradient-to-br from-red-100 to-rose-200"
                                : "bg-gradient-to-br from-cyan-100 to-blue-200"
                            )}>
                              <GitBranch className={cn(
                                "h-5 w-5",
                                isInactive ? "text-red-600" : "text-cyan-600"
                              )} />
                            </div>
                            <div>
                              <p className="font-semibold text-slate-800">{branch.name}</p>
                              <p className="text-xs text-slate-500">{branch.dmaName}</p>
                            </div>
                          </div>
                        </TableCell>

                        {/* Engineers Count */}
                        <TableCell className="py-4 px-6 text-center">
                          <Badge variant="outline" className="text-sm font-medium">
                            {branch.engineerCount}
                          </Badge>
                        </TableCell>

                        {/* Teams Count */}
                        <TableCell className="py-4 px-6 text-center">
                          <Badge variant="outline" className="text-sm font-medium">
                            {branch.teamCount}
                          </Badge>
                        </TableCell>

                        {/* Status */}
                        <TableCell className="py-4 px-6">
                          <EntityStatusBadge status={branch.status as EntityStatus} />
                        </TableCell>

                        {/* Actions */}
                        <TableCell className="py-4 px-6 text-right">
                          <DropdownMenu>
                            <DropdownMenuTrigger asChild>
                              <Button 
                                variant="ghost" 
                                size="icon" 
                                className="h-9 w-9 rounded-lg hover:bg-slate-100 transition-colors"
                              >
                                <MoreHorizontal className="h-4 w-4 text-slate-500" />
                                <span className="sr-only">Actions</span>
                              </Button>
                            </DropdownMenuTrigger>
                            <DropdownMenuContent 
                              align="end" 
                              className="w-48 rounded-xl shadow-lg shadow-slate-200/50 border-slate-200/60"
                            >
                              <DropdownMenuItem 
                                onClick={() => openEditDialog(branch)} 
                                className="rounded-lg gap-2 cursor-pointer"
                              >
                                <Pencil className="h-4 w-4 text-cyan-500" />
                                Edit Branch
                              </DropdownMenuItem>
                              <DropdownMenuItem
                                onClick={() => setDeleteBranch(branch)}
                                className={cn(
                                  "rounded-lg gap-2 cursor-pointer",
                                  hasData 
                                    ? "text-slate-400 cursor-not-allowed" 
                                    : "text-red-600 focus:text-red-600 focus:bg-red-50"
                                )}
                                disabled={hasData}
                              >
                                <Trash2 className="h-4 w-4" />
                                Delete Branch
                              </DropdownMenuItem>
                              {hasData && (
                                <div className="px-2 py-1.5 text-xs text-slate-500 flex items-center gap-1">
                                  <AlertTriangle className="h-3 w-3" />
                                  Has associated data
                                </div>
                              )}
                            </DropdownMenuContent>
                          </DropdownMenu>
                        </TableCell>
                      </TableRow>
                    )
                  })
                )}
              </TableBody>
            </Table>
          </div>
        </CardContent>
      </Card>

      {/* Create/Edit Dialog */}
      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent className="sm:max-w-md bg-white/95 backdrop-blur-xl border-slate-200/50 shadow-2xl shadow-slate-200/50 rounded-2xl">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2 text-xl">
              <div className="h-8 w-8 rounded-lg bg-gradient-to-br from-cyan-500 to-blue-600 flex items-center justify-center">
                {editingBranch ? (
                  <Pencil className="h-4 w-4 text-white" />
                ) : (
                  <Plus className="h-4 w-4 text-white" />
                )}
              </div>
              {editingBranch ? "Edit Branch" : "Add Branch"}
            </DialogTitle>
          </DialogHeader>
          <div className="flex flex-col gap-5 py-4">
            {/* DMA & Utility Info */}
            <div className="rounded-xl border border-cyan-200/80 bg-gradient-to-r from-cyan-50/50 to-blue-50/50 p-4">
              <div className="flex items-center gap-2 text-sm">
                <Building2 className="h-4 w-4 text-cyan-600" />
                <span className="font-semibold text-cyan-700">{dma?.name || "Your DMA"}</span>
                <span className="text-cyan-400">•</span>
                <span className="text-cyan-600 text-xs">{utilityName}</span>
              </div>
              <p className="text-xs text-cyan-500/80 mt-2">
                Branches are automatically assigned to your DMA and utility
              </p>
            </div>

            <div className="flex flex-col gap-2">
              <Label htmlFor="branch-name" className="text-sm font-medium text-slate-700">Branch Name</Label>
              <Input
                id="branch-name"
                value={formName}
                onChange={(e) => setFormName(e.target.value)}
                placeholder="e.g., Sandton Branch"
                className="h-11 bg-slate-50/80 border-slate-200/80 rounded-xl focus:border-cyan-400 focus:ring-cyan-400/20"
              />
            </div>
            <div className="flex flex-col gap-2">
              <Label htmlFor="branch-description" className="text-sm font-medium text-slate-700 flex items-center gap-2">
                <FileText className="h-4 w-4" />
                Description (Optional)
              </Label>
              <Textarea
                id="branch-description"
                value={formDescription}
                onChange={(e) => setFormDescription(e.target.value)}
                placeholder="e.g., Main branch serving the northern area..."
                className="min-h-[80px] bg-slate-50/80 border-slate-200/80 rounded-xl focus:border-cyan-400 focus:ring-cyan-400/20 resize-none"
              />
            </div>
            <div className="flex flex-col gap-2">
              <Label className="text-sm font-medium text-slate-700">Status</Label>
              <Select
                value={formStatus}
                onValueChange={(v) => setFormStatus(v as EntityStatus)}
              >
                <SelectTrigger className="h-11 bg-slate-50/80 border-slate-200/80 rounded-xl">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent className="rounded-xl shadow-lg shadow-slate-200/50">
                  <SelectItem value="active" className="rounded-lg">
                    <div className="flex items-center gap-2">
                      <CheckCircle2 className="h-4 w-4 text-emerald-500" />
                      Active
                    </div>
                  </SelectItem>
                  <SelectItem value="inactive" className="rounded-lg">
                    <div className="flex items-center gap-2">
                      <div className="h-4 w-4 rounded-full bg-slate-400" />
                      Inactive
                    </div>
                  </SelectItem>
                </SelectContent>
              </Select>
            </div>
          </div>
          <DialogFooter className="gap-2 sm:gap-0">
            <Button variant="outline" onClick={() => setDialogOpen(false)} className="rounded-xl">
              Cancel
            </Button>
            <Button 
              onClick={handleSubmit}
              className="bg-gradient-to-r from-cyan-500 to-blue-600 hover:from-cyan-600 hover:to-blue-700 text-white shadow-lg shadow-cyan-500/25 rounded-xl"
            >
              {editingBranch ? "Save Changes" : "Create Branch"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Delete Confirmation */}
      <ConfirmDialog
        open={!!deleteBranch}
        onOpenChange={() => setDeleteBranch(null)}
        title="Delete Branch"
        description={
          deleteBranch && (deleteBranch.engineerCount > 0 || deleteBranch.teamCount > 0 || deleteBranch.reportCount > 0)
            ? `Cannot delete "${deleteBranch.name}" because it has associated data (${deleteBranch.engineerCount} engineers, ${deleteBranch.teamCount} teams, ${deleteBranch.reportCount} reports).`
            : `Are you sure you want to delete "${deleteBranch?.name}"? This action cannot be undone.`
        }
        confirmLabel={deleteBranch && (deleteBranch.engineerCount > 0 || deleteBranch.teamCount > 0 || deleteBranch.reportCount > 0) ? undefined : "Delete Branch"}
        onConfirm={deleteBranch && (deleteBranch.engineerCount > 0 || deleteBranch.teamCount > 0 || deleteBranch.reportCount > 0) ? () => setDeleteBranch(null) : handleDelete}
      />
    </div>
  )
}